CREATE TABLE repositories (id TEXT PRIMARY KEY, path TEXT NOT NULL UNIQUE, name TEXT NOT NULL, preferences TEXT NOT NULL DEFAULT '{}', created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE machine_preferences (key TEXT PRIMARY KEY, value TEXT NOT NULL);
CREATE TABLE registry_snapshots (id TEXT PRIMARY KEY, source TEXT NOT NULL, version TEXT NOT NULL, snapshot TEXT NOT NULL, fetched_at DATETIME NOT NULL, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE registry_refreshes (id TEXT PRIMARY KEY, status TEXT NOT NULL, started_at DATETIME NOT NULL, finished_at DATETIME, error TEXT, snapshot_fetched_at DATETIME);
CREATE TABLE installed_agents (id TEXT NOT NULL, version TEXT NOT NULL, source TEXT NOT NULL, license TEXT NOT NULL, distribution TEXT NOT NULL, package_specifier TEXT NOT NULL, launch TEXT NOT NULL, registry_snapshot_fetched_at TEXT NOT NULL, integrity_status TEXT NOT NULL, expected_digest TEXT, observed_digest TEXT, installation_id TEXT NOT NULL DEFAULT '', provenance TEXT, installation_root TEXT, status TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, failure TEXT, is_default INTEGER NOT NULL DEFAULT 0, readiness_status TEXT NOT NULL DEFAULT 'unknown', readiness_error TEXT, readiness_failure TEXT, protocol_version INTEGER, capabilities TEXT, auth_methods TEXT NOT NULL DEFAULT '[]', raw_initialize TEXT, probed_at TEXT, PRIMARY KEY (id, version, distribution, installation_id));
CREATE TABLE installation_operations (id TEXT PRIMARY KEY, agent_id TEXT NOT NULL, version TEXT NOT NULL, package_specifier TEXT NOT NULL, distribution TEXT NOT NULL DEFAULT 'npx', installation_id TEXT NOT NULL DEFAULT '', phase TEXT NOT NULL DEFAULT 'resolving', temporary_root TEXT, published_root TEXT, recovery_metadata TEXT, status TEXT NOT NULL, started_at TEXT NOT NULL, finished_at TEXT, error TEXT, failure TEXT, error_code TEXT, diagnostic TEXT, activation_status TEXT NOT NULL DEFAULT 'not_started', activation_started_at TEXT, activation_finished_at TEXT, activation_error TEXT, activation_error_code TEXT, activation_diagnostic TEXT);
CREATE TABLE agent_authentication_operations (id TEXT PRIMARY KEY, agent_id TEXT NOT NULL, version TEXT NOT NULL, installation_id TEXT NOT NULL DEFAULT '', method_id TEXT NOT NULL, method_name TEXT NOT NULL, method_type TEXT NOT NULL DEFAULT 'agent', status TEXT NOT NULL, started_at TEXT NOT NULL, finished_at TEXT, error TEXT, failure TEXT, terminal_exit_code INTEGER, terminal_signal INTEGER, terminal_output_truncated INTEGER NOT NULL DEFAULT 0, terminal_last_activity_at TEXT, terminal_diagnostic TEXT);
CREATE TABLE agent_removal_operations (id TEXT PRIMARY KEY, agent_id TEXT NOT NULL, version TEXT NOT NULL, installation_id TEXT NOT NULL, status TEXT NOT NULL, started_at TEXT NOT NULL, finished_at TEXT, error TEXT, error_code TEXT, diagnostic TEXT, references_json TEXT NOT NULL DEFAULT '[]');
CREATE TABLE agent_removal_tombstones (installation_id TEXT PRIMARY KEY, agent_id TEXT NOT NULL, version TEXT NOT NULL, provenance TEXT NOT NULL, removed_at TEXT NOT NULL, removal_operation_id TEXT NOT NULL);
CREATE TABLE agent_credential_bindings (installation_id TEXT NOT NULL, variable_name TEXT NOT NULL, credential_ref TEXT NOT NULL, secret INTEGER NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, PRIMARY KEY (installation_id, variable_name));
CREATE TABLE workflow_profiles (id TEXT PRIMARY KEY, repository_id TEXT NOT NULL, name TEXT NOT NULL, permission_policy TEXT NOT NULL, unattended_authorized INTEGER NOT NULL DEFAULT 0, timeout_ms INTEGER NOT NULL, max_retries INTEGER NOT NULL, verification_commands TEXT NOT NULL, require_decorrelated_builder_validator INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, FOREIGN KEY (repository_id) REFERENCES repositories(id) ON DELETE CASCADE);
CREATE TABLE agent_assignments (id TEXT PRIMARY KEY, profile_id TEXT NOT NULL, role TEXT NOT NULL, agent_id TEXT NOT NULL, agent_version TEXT NOT NULL, model TEXT, mode TEXT, agent_provenance TEXT NOT NULL DEFAULT '{}', created_at TEXT NOT NULL, updated_at TEXT NOT NULL, UNIQUE(profile_id, role), FOREIGN KEY (profile_id) REFERENCES workflow_profiles(id) ON DELETE CASCADE);
CREATE INDEX idx_workflow_profiles_repository ON workflow_profiles(repository_id);
CREATE UNIQUE INDEX idx_installed_agents_identity ON installed_agents(id, version, distribution, installation_id);
